@ARTICLE{10.1016/j.jare.2025.06.041,
	author = {Shi R(1) and Wei J(2) and Ye J(3) and Song X(4) and Yang X(5) and Zhang Y(6) and Liu S(7) and Ren J(7) and Wang D(8) and Zhao Z(8) and Liu Z(8) and Wang Y(8) and Zhao B(8) and Xiao C(8) and Dai X(9) and Ai L(10) and Liu X(11).},
	title = {The novel synbiotic (Lactiplantibacillus plantarum and galacto-oligosaccharides) ameliorates obesity-related metabolic dysfunction: Arginine as a key mediator signaling molecule.},
	abstract = {OBJECTIVE: This study aimed to develop a novel synbiotic composed of Lactiplantibacillus plantarum LLY-606 and galacto-oligosaccharides (GOS) to improve lipid metabolism in obesity. DESIGN: Through genome-wide analysis using COG and CAZy databases, we identified GOS as a specific growth substrate for Lactiplantibacillus plantarum LLY-606. The efficacy of this synbiotic (LP-GOS) was evaluated in both obese individuals and high-fat diet-induced obese mice. RESULTS: LP-GOS supplementation reduced visceral fat and waist circumference in humans and attenuated obesity in mice. It also improved gut microbiota composition and increased serum arginine levels. Metabolomic and microbiota analyses suggested that enhanced arginine production plays a key role. This was further confirmed by arginine synthesis inhibition, antibiotic treatment, and CRISPR-Cas9-mediated knockout of the Ass1 gene in Lactiplantibacillus plantarum LLY-606. These interventions demonstrated that LP-GOS improves lipid metabolism through arginine-mediated activation of the AMPK pathway. CONCLUSIONS: LP-GOS effectively alleviates obesity-associated lipid metabolism disorders by enhancing arginine production and activating the AMPK signaling pathway.},
	doi = {10.1016/j.jare.2025.06.041},
	pmid = {40545235 [Indexed for MEDLINE]},
	note = {PMC12957849}
}

